-- Enrichment marathon batch: Restreamer, Resy, Retool, RetroShare, Reveal, revealjs, Revel Systems, RevenueCat

-- ── Restreamer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted streaming server that lets anyone publish live RTMP or SRT video to YouTube, Twitch, Facebook, Vimeo, and other platforms without recurring license fees.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Germany (open-source project)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Restreamer Review 2026: Free Open-Source Self-Hosted Streaming Server$q$, seo_title),
  seo_meta_description = COALESCE($q$Restreamer by datarhei is a free, open-source, self-hosted live streaming server for RTMP and SRT publishing to YouTube, Twitch, Facebook, and Vimeo, with no license costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Restreamer is a free and open-source, self-hosted live streaming server maintained by the datarhei project, which began around 2015 in Germany and is led by developers including Jan Stabenow and Sven Erbeck. Distributed with no ongoing license costs, its source is published on GitHub as datarhei/restreamer, and it is built to run on infrastructure the user fully controls rather than as a hosted SaaS product, which distinguishes it sharply from paid multistreaming platforms such as Restream.io. The software ships as a Docker or Podman container and runs on Linux, macOS, Windows, Raspberry Pi, and other single-board computers, with a Raspberry Pi 4 or newer recommended for reliable performance. Once deployed, Restreamer exposes a browser-based admin panel with a setup wizard that lets a user configure live inputs from OBS, IP cameras, USB devices, network sources, or a Raspberry Pi camera module, and then republish that stream via built-in RTMP and SRT servers to destinations like YouTube, Twitch, Facebook, and Vimeo, or to custom RTMP endpoints such as Wowza. It supports more than 50 video formats, GPU-accelerated encoding, HDMI output, free HTTPS certificates via Let's Encrypt, and built-in logging plus system and user monitoring, giving operators full data ownership since no video ever has to pass through a third-party cloud service. Because Restreamer is entirely self-hosted, there are no subscription tiers, seat limits, or feature paywalls of the kind found in commercial restreaming SaaS tools; the only costs are the hardware and bandwidth an operator supplies. This makes it popular with hobbyist streamers, churches, schools, community broadcasters, and privacy-conscious organizations that want to avoid recurring fees or vendor lock-in for a single always-on live feed or an appliance-style streaming box. The tradeoff is that Restreamer requires the user to manage their own server, networking, and uptime, and it lacks the built-in multistreaming-to-many-platforms-simultaneously dashboard, analytics, and customer support that paid SaaS competitors provide. Documentation and community support are available through the project's GitHub repository, Docker Hub image, and official docs site, and the project accepts community funding through Open Collective and Patreon. For anyone specifically searching for a no-cost, developer-friendly, open-source alternative to commercial restreaming services, Restreamer is one of the most established options, with an active codebase and a track record stretching back roughly a decade.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f3b942d1-643e-4d8c-b830-41cfe23c130e';

