-- ── Resy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Restaurant reservation and table-management platform owned by American Express, used by diners to book tables and by restaurants to manage reservations, waitlists, and guest data.$q$, short_description),
  pricing_model = COALESCE($q$Free for diners; subscription (ResyOS) for restaurants$q$, pricing_model),
  starting_price = COALESCE($q$$249/month (ResyOS Platform plan for restaurants)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Resy Review 2026: Pricing, Features and How It Works for Restaurants$q$, seo_title),
  seo_meta_description = COALESCE($q$Resy is American Express's restaurant reservation platform. See ResyOS pricing plans, features, and how it compares for diners and restaurant operators in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Resy is a restaurant reservation and table-management platform founded in 2014 in New York City by Ben Leventhal, Gary Vaynerchuk, and Michael Montero, with early backing from investors including Airbnb and Union Square Hospitality Group. American Express acquired Resy in 2019, and the platform has operated as part of Amex's dining and lifestyle business ever since, including through the widely used Amex Resy Credit built into certain American Express cards. On the consumer side, Resy is free to use: diners search, book, and manage restaurant reservations through the Resy website and mobile app, join waitlists, and receive notifications when hard-to-get tables open up. On the restaurant side, Resy operates as ResyOS, a paid subscription platform for table management, reservations, guest CRM, POS integrations, and analytics. Following American Express's 2024 acquisition of Tock for roughly 400 million dollars, Amex began folding Tock's restaurant base into Resy in 2026, expanding the combined network past 25,000 venues and adding features like event ticketing and prepayment tools that originated on Tock. As of 2026, ResyOS offers four subscription tiers for restaurants: Platform at 249 dollars per month (reservation and table management with POS integrations), Platform 360 at 399 dollars per month (adds advanced analytics and automated guest insights), and two Tock-powered tiers, Essential at 269 dollars per month and Premium at 399 dollars per month, which add event ticketing, prepayment handling, and, on Premium, POS integrations and premium support. All ResyOS tiers charge a flat monthly fee with no per-cover or per-reservation fee, which differentiates Resy's pricing model from competitors like OpenTable that can charge per-seated-diner fees. Common features across every tier include table and waitlist management, automated guest alerts, credit-card-backed reservation holds and cancellation fees, deposits, and chat or email support, while higher tiers add phone support, booking APIs, chargeback protection, and access to exclusive VIP booking groups. Resy is best known among consumers for its role in Amex's dining benefits program and for partnerships with high-demand restaurants in major U.S. cities, and among restaurant operators for its flat-fee pricing model as an alternative to commission-based reservation platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de627a61-90d5-4b28-8678-2d3f4251e213';

