-- ── RetroShare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, decentralized platform for encrypted chat, file sharing, forums, and voice/video calls built directly between trusted friend-to-friend nodes.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$and multiple community-translated languages$q$]::text[],
  seo_title = COALESCE($q$RetroShare Review 2026: Free Decentralized Encrypted Communication Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$RetroShare is a free, open-source, decentralized platform for encrypted chat, file sharing, forums, and calls between trusted friend-to-friend nodes. See features and how it works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RetroShare is a free, open-source, decentralized communication platform that was founded in 2006 by a developer known by the handle drbob to enable secure, private communication and file sharing directly between trusted friends, without relying on centralized servers. Over time additional contributors joined the project, including a developer known as Crypton who built the Qt-based graphical interface still used today, and the software has continued under active open-source development for roughly two decades. RetroShare works by establishing encrypted connections, secured with OpenPGP and OpenSSL, directly between a user and people they explicitly add as friends, forming a distributed friend-to-friend network rather than a client-server system or a fully open peer-to-peer swarm like BitTorrent. On top of that encrypted network, RetroShare layers several distributed services: private and group chat, including distant chat that can reach friends-of-friends through anonymous tunnels; forums and boards that sync automatically between friends and can be read and written offline, making them resistant to censorship since there is no central server to shut down; a mail-like private messaging system that stores messages on friends' nodes so they can be delivered even while a recipient is offline; file sharing that uses swarming techniques similar to BitTorrent to speed up transfers of large files; and, through an optional VoIP plugin, encrypted voice and video calls between connected peers. Because only direct friends can see what a user shares or downloads, and traffic to more distant network members is anonymized through tunneling, RetroShare is positioned as a privacy- and censorship-resistant alternative to mainstream chat and file-sharing platforms. It is entirely free and open source, with no subscription fees, no advertising, and no formal terms of service, and it is available on Windows, macOS, Linux, and Android. As a community-maintained project rather than a commercial company, RetroShare has no headquarters, employee count, or revenue model in the conventional sense; its ongoing development instead relies on volunteer contributors coordinating through GitHub and community documentation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '456fbc5c-1126-4664-96da-4a376804c0f8';

