-- ── Reveal ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered eDiscovery, document review, legal hold, and investigations platform used by corporate legal teams, law firms, and government agencies.$q$, short_description),
  pricing_model = COALESCE($q$Custom / quote-based enterprise pricing$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$500+ employees (post Reveal-Brainspace merger)$q$, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Reveal (RevealData) Review 2026: AI eDiscovery Platform Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Reveal (RevealData) is an AI-powered eDiscovery and document review platform for legal teams. See its history, Brainspace merger, key features, and pricing model.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Reveal, operating as RevealData, is an AI-powered eDiscovery, document review, legal hold, and investigations platform headquartered in Chicago, Illinois, with roots dating back to 2009 under founder and CEO Wendell Jisa. The company's current form took shape in January 2021, when Reveal merged with Brainspace, an artificial intelligence and analytics engine used across eDiscovery, cybersecurity, and fraud investigation workflows; the combined company was backed by more than 200 million dollars in investment from K1 Investment Management. Reveal had previously grown through acquisitions of Mindseye in 2019 and NexLP in 2020, folding additional AI, analytics, and workflow capabilities into its platform ahead of the Brainspace merger. Today Reveal serves corporate legal departments, law firms, legal service providers, government agencies, and educational institutions, reporting more than 4,000 customers across over 50 countries, with a workforce that industry data places at roughly 500 employees and estimated annual revenue in the hundreds of millions of dollars. The Reveal platform covers the full eDiscovery Reference Model, from identifying and preserving data, through collection, processing, review, and analysis, to production and courtroom or hearing presentation. Its most prominent recent capability is a generative AI layer called aji, paired with a natural-language query tool called ASK that lets legal teams interrogate large document sets directly in plain English, and a structured AI-powered document review workflow that applies predictive coding, concept clustering, and relevance scoring at scale. Reveal also maintains a library of more than 25 pre-built AI models tuned for specific legal scenarios, such as antitrust investigations, personally identifiable information detection, and HR matters, which legal teams can use out of the box or customize for their own case data. Because Reveal sells to enterprise legal and corporate customers with highly variable data volumes and case complexity, it does not publish self-serve pricing; prospective customers get quotes tailored to data volume, user count, and specific modules needed, typical of enterprise legal technology and eDiscovery software. It is important not to confuse Reveal/RevealData, the legal AI and eDiscovery company, with reveal.js, an unrelated open-source HTML presentation framework that happens to share a similar name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9f433b75-2930-48b2-9563-119f142dab72';

