-- ── revealjs ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source HTML presentation framework that lets anyone build interactive, code-based slide decks using web technologies.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (MIT license)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$reveal.js Review 2026: Free Open-Source HTML Presentation Framework$q$, seo_title),
  seo_meta_description = COALESCE($q$reveal.js is a free, MIT-licensed, open-source HTML presentation framework by Hakim El Hattab. See features, plugins, and how it compares to slide software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$reveal.js is a free, open-source HTML presentation framework created by Swedish front-end developer and interface designer Hakim El Hattab, who first released it in 2011 and continues to maintain it today. Distributed under the MIT license through its GitHub repository (hakimel/reveal.js) and npm package, reveal.js lets anyone with a web browser build fully-featured, interactive slide presentations using standard web technologies rather than proprietary slide software. Because a reveal.js deck is just an HTML page, presenters can do anything on a slide that they could do on any web page, including styling with custom CSS, embedding external pages via iframes, pulling in live data, or adding custom behavior through reveal.js's JavaScript API. Core features include nested (vertical and horizontal) slides, Markdown support for writing slide content in plain text, an Auto-Animate feature that smoothly transitions matching elements between slides, PDF export for offline sharing or printing, speaker notes with a dedicated presenter view that includes a timer and a preview of the upcoming slide, LaTeX typesetting for mathematical content, syntax-highlighted code blocks, and an extensive plugin and API ecosystem for customization. Presentations built with reveal.js are responsive by default, scaling to fit different screen sizes and devices, and support custom themes, transition styles, parallax backgrounds, and configurable keyboard bindings. Because it requires no installation for viewers, a reveal.js presentation can be shared as a static HTML page or bundled into a build pipeline with tools like Webpack or Vite for larger projects. The npm package has accumulated tens of thousands of GitHub stars, reflecting its status as one of the most widely used open-source tools among developers, technical conference speakers, and educators who prefer building slides in code rather than in dedicated slide-design software. It is completely free for any use, with no paid tiers, subscriptions, or company behind it, distinguishing it entirely from RevealData/Reveal, an unrelated commercial legal eDiscovery platform that happens to share a similar name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4f61c5d6-c000-4e54-918d-cc68123a94de';

