-- ── RevenueCat ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Backend-as-a-service platform that unifies in-app purchase and subscription management across iOS, Android, and the web for mobile app developers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / revenue-share (percentage of tracked revenue above a free threshold), with custom Enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free up to $2,500 in monthly tracked revenue, then 1% above that threshold$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$~150-170 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RevenueCat Review 2026: Pricing, Features and How It Works$q$, seo_title),
  seo_meta_description = COALESCE($q$RevenueCat is a backend platform for managing in-app purchases and subscriptions across iOS, Android, and the web. See 2026 pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RevenueCat is a backend-as-a-service platform for managing in-app purchases and subscriptions, founded in 2017 by Jacob Eiting and Miguel Carranza and headquartered in San Francisco, California. Backed by Y Combinator and reporting a headcount in the range of roughly 150 to 170 employees, RevenueCat has grown to power subscription infrastructure for more than 30,000 apps. The platform's core purpose is to abstract away the complexity of Apple's StoreKit and Google Play Billing, giving mobile developers a single, unified API and dashboard to manage purchases, entitlements, and subscriber data across iOS, Android, and the web, instead of building and maintaining separate billing integrations for each platform. Beyond the core subscription backend, RevenueCat's product suite includes open-source SDKs for all major platforms, a comprehensive REST API, pre-built integrations with mobile measurement partners (MMPs) for real-time purchase attribution, A/B testing with remote configuration, a native paywall editor with templates for building and iterating on paywalls without app-store resubmission, audience segmentation and targeting, a dashboard covering more than 40 monetization metrics, automated subscription support tooling, cross-platform customer insights, promotional subscription management, and event-based lifecycle campaign triggers. RevenueCat's 2026 pricing follows a straightforward revenue-share model rather than traditional seat licenses: the Pro plan is free for apps generating up to 2,500 dollars in monthly tracked revenue (MTR), after which RevenueCat charges 1 percent of tracked revenue above that threshold, with no per-transaction fees, seat licenses, or enterprise minimums built into the base structure. RevenueCat also offers an alternative Growth Tools pricing path for teams that want to use their own backend infrastructure and only pay a 1 percent MTR fee on conversions driven through specific tools like the paywall editor or web-to-app funnels. For companies with high transaction volume or specialized requirements, RevenueCat offers a custom-priced Enterprise plan that adds volume discounts, flexible tracking configurations, dedicated support, and custom SLAs. This pricing model, which scales with an app's actual revenue rather than charging flat fees regardless of usage, has made RevenueCat particularly popular among indie developers and early-stage mobile startups, while its analytics, experimentation, and paywall tools have also attracted larger app publishers looking to consolidate subscription infrastructure and monetization experimentation into a single platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd89ed73f-80e0-4221-8c89-5c539a41247e';

