INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Self-hosted architecture$q$, $q$Runs entirely on infrastructure the user controls, whether a Raspberry Pi, on-premises server, or cloud VM, so video never has to pass through a third-party service.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$RTMP and SRT publishing$q$, $q$Built-in RTMP and SRT servers let operators receive a live feed from OBS or a camera and republish it to YouTube, Twitch, Facebook, Vimeo, or custom endpoints like Wowza.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Docker and Podman deployment$q$, $q$Ships as a container image that installs in minutes on Linux, macOS, Windows, Raspberry Pi, and other single-board computers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Setup wizard and admin panel$q$, $q$A browser-based admin interface with a guided setup wizard makes configuring new live streams straightforward without command-line work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Wide format and hardware support$q$, $q$Supports more than 50 video formats plus GPU encoding, HDMI output, and camera input from USB, network, virtual, and Raspberry Pi camera sources.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Free HTTPS via Let's Encrypt$q$, $q$Built-in support for free SSL certificates secures the admin panel and stream endpoints without extra configuration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Logging and monitoring$q$, $q$Includes user and system monitoring plus logging so operators can track stream health and server performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$No licensing costs$q$, $q$Distributed as open-source software with no subscription fees, watermarks, or usage caps for private or commercial use.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Completely free for personal and commercial use with no recurring license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Full data ownership since streams run on infrastructure the operator controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Lightweight enough to run on a Raspberry Pi for low-cost, always-on streaming appliances$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Open-source codebase with an active GitHub community and Docker-based deployment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Supports multiple simultaneous input sources and more than 50 video formats$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Requires the user to manage their own server, networking, and uptime$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$No built-in customer support team; help comes from community docs and GitHub$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Lacks the unified multi-destination dashboard and analytics of paid restreaming SaaS tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Initial setup requires more technical comfort than a hosted, no-install product$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Scaling to many simultaneous streams requires the operator to provision more hardware$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Is Restreamer really free to use?$q$, $q$Yes. Restreamer is open-source software with no ongoing license costs for private or commercial use; the only expenses are the hardware, hosting, and bandwidth an operator supplies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Is Restreamer the same product as Restream.io?$q$, $q$No. Restreamer (by the datarhei project) is a free, self-hosted, open-source streaming server, while Restream.io is a separate, unrelated paid SaaS multistreaming platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$What hardware do I need to run Restreamer?$q$, $q$Restreamer runs via Docker or Podman on Linux, macOS, Windows, and single-board computers; the project recommends a Raspberry Pi 4 or newer, though it also runs on earlier Raspberry Pi models.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Which platforms can I stream to with Restreamer?$q$, $q$Restreamer can republish a live stream to YouTube, Twitch, Facebook, Vimeo, and other RTMP-compatible services such as Wowza.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Does Restreamer require an internet connection to set up?$q$, $q$You need an internet connection to pull the Docker image and, typically, to reach streaming destinations, but the server itself can run on a local network or on-premises hardware.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Who maintains Restreamer?$q$, $q$Restreamer is maintained by the datarhei open-source project, whose Restreamer and Core codebases are hosted publicly on GitHub.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Can I use Restreamer for commercial broadcasts?$q$, $q$Yes, the license permits both private and commercial use at no cost.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Hobbyist and community live streaming$q$, $q$Individuals, churches, and community groups use Restreamer on low-cost hardware like a Raspberry Pi to run an always-on live feed to YouTube or Facebook without paying a monthly SaaS fee.$q$, $q$Hobbyists and community broadcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Privacy-conscious self-hosted broadcasting$q$, $q$Organizations that want full control of their video data deploy Restreamer on their own servers instead of routing streams through a third-party cloud platform.$q$, $q$Privacy-focused organizations and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Low-cost streaming appliances$q$, $q$Developers build dedicated streaming boxes or kiosks using Restreamer's Docker image on single-board computers for events, security cameras, or digital signage.$q$, $q$Developers and system integrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment via Docker or Podman","RTMP and SRT publishing to YouTube, Twitch, Facebook, Vimeo, and custom endpoints","No license fees for private or commercial use","Community support via GitHub and documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Restreamer is an open-source live streaming server developed by the datarhei project that packages FFmpeg-based ingest and republishing tools behind a simple web admin interface. It is designed to be self-hosted on a server, virtual machine, or single-board computer such as a Raspberry Pi, giving the operator complete control over their video data instead of routing it through a third-party cloud platform.$q$, $q$Because it runs under an open license with no recurring fees, Restreamer is often used as a free alternative to commercial restreaming SaaS products for operators who are comfortable managing their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Restreamer accepts input from OBS, IP cameras, USB and network video sources, and Raspberry Pi camera modules, then republishes the stream through built-in RTMP and SRT servers to platforms like YouTube, Twitch, Facebook, and Vimeo, or to any custom RTMP-compatible destination such as Wowza.$q$, $q$The software includes a setup wizard, a simplified admin panel, support for more than 50 video formats, GPU encoding, HDMI output, free Let's Encrypt HTTPS certificates, and basic logging and system monitoring, all packaged for deployment via Docker or Podman on Linux, macOS, Windows, or Raspberry Pi hardware.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Restreamer is completely free for both private and commercial use, with no ongoing license costs, seat limits, or feature paywalls. Operators only pay for the hardware, hosting, and bandwidth needed to run the server themselves.$q$, $q$Because there is no vendor-hosted tier, total cost of ownership depends entirely on where and how the server is deployed, from a low-cost Raspberry Pi 4 at home to a cloud VM or on-premises server for organizations with heavier streaming needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f3b942d1-643e-4d8c-b830-41cfe23c130e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Free consumer booking$q$, $q$Diners can search, reserve, and manage restaurant tables at no cost through the Resy website and mobile app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Flat-fee restaurant pricing$q$, $q$ResyOS charges restaurants a fixed monthly rate instead of a per-cover fee, unlike commission-based competitors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Table and waitlist management$q$, $q$Restaurant staff manage floor plans, seating, and walk-in waitlists from a single dashboard.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Automated guest alerts$q$, $q$Automated alerts tell restaurants when a repeat or VIP guest books, and tell diners when a sold-out table opens up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Deposits and cancellation protection$q$, $q$Credit-card-backed reservation holds, deposits, and cancellation fees help restaurants reduce no-shows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$POS and analytics integrations$q$, $q$Higher ResyOS tiers connect with point-of-sale systems and provide advanced guest and revenue analytics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Tock-powered event ticketing$q$, $q$Following the Tock integration, Essential and Premium plans add ticketed prix-fixe events and prepayment collection.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$American Express card benefits$q$, $q$Resy powers the Amex Resy Credit, a recurring dining statement credit available on select American Express cards.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Flat monthly pricing for restaurants with no per-cover fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Free for diners with a large network of well-known restaurants, especially in major U.S. cities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Backed by American Express, giving it strong brand recognition and card-linked benefits$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Growing network following the 2026 integration of Tock's restaurant base$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Automated no-show protection tools like deposits and card-backed holds$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Restaurant subscription fees start relatively high at 249 dollars per month regardless of covers seated$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Network still skews toward restaurants in and around major cities$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Amex Resy Credit eligibility rules for consumers have changed and require checking eligibility at time of booking$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Ongoing Tock integration in 2026 has created some transitional complexity for restaurants and diners$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Owned by American Express, which limits independence compared to standalone reservation platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Who owns Resy?$q$, $q$American Express acquired Resy in 2019, and Resy has operated as part of Amex's dining and lifestyle business since then.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Is Resy free for diners?$q$, $q$Yes, searching for and booking restaurant reservations through the Resy app and website is free for consumers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$How much does Resy cost restaurants?$q$, $q$As of 2026, ResyOS plans for restaurants range from 249 to 399 dollars per month depending on the tier, with no per-cover fees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$What is the difference between Resy and Tock?$q$, $q$Tock was a separate reservation platform that American Express acquired in 2024; Amex has been integrating Tock's restaurant network and features, like event ticketing, into Resy starting in 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$What is the Amex Resy Credit?$q$, $q$It is a recurring statement credit offered on select American Express cards for dining at eligible Resy restaurants, subject to eligibility rules that can change.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$When was Resy founded?$q$, $q$Resy was founded in 2014 in New York City by Ben Leventhal, Gary Vaynerchuk, and Michael Montero.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Does Resy charge restaurants per reservation?$q$, $q$No, ResyOS uses flat monthly subscription pricing rather than per-cover or per-reservation fees.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Booking hard-to-get restaurant reservations$q$, $q$Diners use Resy to search availability, join waitlists, and get notified when tables open at in-demand restaurants.$q$, $q$Restaurant diners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Restaurant table and reservation management$q$, $q$Restaurants subscribe to ResyOS to manage their floor plan, reservations, waitlists, and guest history from one system.$q$, $q$Restaurant owners and hosts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Reducing no-shows with deposits$q$, $q$Restaurants use Resy's card-backed holds, deposits, and cancellation fees to protect revenue from no-show diners.$q$, $q$Restaurant operations managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Platform$q$, $q$$249$q$, $q$per month$q$, NULL, $q$["Reservation and table management","POS integrations","Automated guest alerts","Credit-card-backed holds and cancellation fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Platform 360$q$, $q$$399$q$, $q$per month$q$, NULL, $q$["Everything in Platform","Advanced analytics","Automated guest insights"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Essential (Tock-powered)$q$, $q$$269$q$, $q$per month$q$, NULL, $q$["Reservation and table management","Advanced customization","Event ticketing","3 percent fee on prepayments"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$Premium (Tock-powered)$q$, $q$$399$q$, $q$per month$q$, NULL, $q$["Everything in Essential","2 percent prepayment fee","POS integrations","Premium support","Experience tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resy is a restaurant reservation platform founded in 2014 in New York City and acquired by American Express in 2019. It serves two audiences: diners, who use the free Resy app and website to find and book tables, and restaurants, who subscribe to ResyOS for reservation, table, and guest-management tools.$q$, $q$In 2026, American Express has been integrating its Tock platform, acquired in 2024, into Resy, expanding the combined restaurant network past 25,000 venues and bringing event-ticketing and prepayment features that originated on Tock into the broader Resy product line.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$For diners, Resy offers reservation search and booking, waitlist notifications for hard-to-book restaurants, and integration with the Amex Resy Credit benefit available on certain American Express cards.$q$, $q$For restaurants, ResyOS provides table and floor management, automated guest alerts, credit-card-backed cancellation policies and deposits, POS integrations, guest CRM and analytics, and, on Tock-powered tiers, event ticketing and prepayment tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de627a61-90d5-4b28-8678-2d3f4251e213', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ResyOS charges restaurants a flat monthly subscription rather than a per-cover fee. As of 2026, plans include Platform at 249 dollars per month, Platform 360 at 399 dollars per month, Essential (Tock-powered) at 269 dollars per month with a 3 percent prepayment fee, and Premium (Tock-powered) at 399 dollars per month with a reduced 2 percent prepayment fee.$q$, $q$Resy remains free for consumers to search, book, and manage reservations through its app and website.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Drag-and-drop UI builder$q$, $q$Assemble internal app interfaces from pre-built components like tables, forms, charts, and buttons without writing front-end code from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Broad data source connectivity$q$, $q$Connects to PostgreSQL, MySQL, MongoDB, REST APIs, GraphQL, and dozens of other integrations out of the box.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Custom logic with code$q$, $q$Supports JavaScript, Python, and SQL directly inside the builder for custom transformations and business logic.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Retool Workflows$q$, $q$Automate backend processes and scheduled jobs visually, separate from the front-end app builder.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Retool Database$q$, $q$A built-in Postgres-compatible database for teams that need a data store without standing up separate infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Retool Mobile$q$, $q$Extend internal tools to native mobile apps for field or on-the-go employees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Enterprise access controls$q$, $q$Higher tiers add SSO, audit logging, granular permissions, and independent workspaces for larger organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$AI-assisted app building$q$, $q$Includes AI credits and features for generating app components and agents inside the builder.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Dramatically speeds up building internal tools compared to custom front-end development$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Wide range of native integrations with databases and APIs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Free tier makes it easy for small teams to start without upfront cost$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Backed by strong funding and investor support, suggesting long-term product investment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Expanded product suite (Workflows, Database, Mobile, AI) covers more than just the original app builder$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Per-builder pricing can get expensive as engineering teams and internal-user counts grow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Enterprise features like SSO and audit logging require the custom-priced top tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Requires some coding knowledge (JavaScript/SQL) for anything beyond basic layouts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$As a hosted platform, teams take on dependency risk for business-critical internal tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Business and Enterprise tier pricing requires talking to sales for exact costs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$What is Retool used for?$q$, $q$Retool is used to build internal business applications, such as admin panels, dashboards, and CRUD tools, by connecting to existing databases and APIs and assembling the interface from pre-built components.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Who founded Retool and when?$q$, $q$Retool was founded in 2017 by David Hsu and is headquartered in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Does Retool have a free plan?$q$, $q$Yes, Retool's Free plan supports up to five builders and five end users at no cost, with limited workflow runs and AI credits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$How much does Retool cost?$q$, $q$Paid plans start around 10 dollars per builder per month on the Team plan (annual billing), rising to roughly 50 dollars per builder per month on the Business plan, with custom Enterprise pricing above that.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$What data sources can Retool connect to?$q$, $q$Retool connects to databases like PostgreSQL, MySQL, and MongoDB, as well as REST and GraphQL APIs and dozens of other native integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Does Retool support mobile apps?$q$, $q$Yes, Retool Mobile lets teams build and deploy internal tools as native mobile apps.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Is Retool only for developers?$q$, $q$Retool is primarily designed for developers and technical builders, since custom logic uses JavaScript, Python, or SQL, though non-technical staff can be added as end users of the finished apps.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Internal admin panels and dashboards$q$, $q$Engineering teams build admin tools to manage customers, orders, or content without dedicating front-end resources to custom builds.$q$, $q$Software engineering and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Operations and support tooling$q$, $q$Operations and customer support teams get purpose-built internal apps for tasks like refund processing or account lookups, connected directly to production databases and APIs.$q$, $q$Operations and customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Workflow automation$q$, $q$Teams use Retool Workflows to automate backend processes, such as data syncing or scheduled reporting, alongside their internal apps.$q$, $q$Data and backend engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 5 builders and 5 end users","Unlimited web and mobile apps","500 workflow runs per month","5GB storage","250 AI credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Team$q$, $q$$10 per builder per month (annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Free","5,000 workflow runs per month","Staging environment","App release versions","Additional end users at $5/month each"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Business$q$, $q$$50 per builder per month (annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Team","Audit logging","Rich permission controls","Portals and embedded apps","Unlimited environments and modules"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$Enterprise$q$, $q$Custom$q$, $q$annual (negotiated)$q$, NULL, $q$["Everything in Business","SAML and OpenID Connect SSO","Source control integration","Custom branding","Independent workspaces","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Retool is a low-code platform, founded in 2017 by David Hsu and headquartered in San Francisco, designed to help engineering teams quickly build internal tools such as admin panels, dashboards, and CRUD applications. Rather than building these interfaces from scratch, developers connect Retool to their existing databases and APIs and assemble the UI from pre-built components.$q$, $q$The company has raised roughly 165 million dollars from investors including Sequoia Capital and Y Combinator and was valued at around 3.2 billion dollars in recent funding rounds, with a headcount that has grown past 400 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Retool's core builder combines drag-and-drop UI components (tables, forms, charts, buttons) with a code layer supporting JavaScript, Python, and SQL for custom logic, and connects natively to databases like PostgreSQL and MySQL as well as REST and GraphQL APIs.$q$, $q$The platform has expanded beyond the original web app builder to include Retool Workflows for backend automation and scheduled jobs, Retool Mobile for internal mobile apps, Retool Database as a built-in data store, and AI features for embedding agents or generating app scaffolding.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('395c608c-5d39-431e-9dd4-670981dd1352', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Retool offers a Free plan for up to five builders and five end users, a Team plan at roughly 10 dollars per builder per month (annual billing), and a Business plan at roughly 50 dollars per builder per month (annual billing), each adding more workflow runs, AI credits, and administrative controls.$q$, $q$Enterprise pricing is custom and adds SSO, source control, custom branding, and dedicated support; internal end users beyond the included allotment are billed separately at a lower per-user rate on paid plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Friend-to-friend encrypted network$q$, $q$Builds direct encrypted connections only with explicitly trusted friends, secured with OpenPGP and OpenSSL.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Decentralized forums and boards$q$, $q$Censorship-resistant forums sync automatically between friends and can be read and written offline.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Distant chat via anonymous tunnels$q$, $q$Lets users securely message friends-of-friends through the network using anonymous routing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Store-and-forward messaging$q$, $q$Private messages are stored on friends' nodes so they can still be delivered when a recipient comes back online.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Swarming file sharing$q$, $q$Uses BitTorrent-like swarming to speed up transfers of large files between friends or the wider network.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Optional VoIP plugin$q$, $q$Adds encrypted voice and video calling between connected peers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Cross-platform availability$q$, $q$Available on Windows, macOS, Linux, and Android.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$No central server$q$, $q$Fully decentralized architecture means there is no company-run server that can be shut down or subpoenaed for user data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Completely free with no subscription or hidden costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Strong privacy model based on friend-to-friend encryption rather than centralized servers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Censorship-resistant forums and messaging with offline sync$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Open-source codebase that anyone can audit$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Supports large file sharing through swarming technology$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Requires manually adding and verifying friends, which limits network reach compared to open platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$No official company support; help comes only from community documentation and forums$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Interface and setup are more technical than mainstream chat apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Network effects are weaker since you can only reach people through friend connections$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Development pace and updates depend entirely on volunteer contributors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Is RetroShare really free?$q$, $q$Yes, RetroShare is fully free and open source with no subscription fees, ads, or hidden costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$How is RetroShare different from Tor or VPNs?$q$, $q$RetroShare builds encrypted connections directly between trusted friends rather than anonymizing traffic through a shared relay network, forming a friend-to-friend rather than fully anonymous network.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Who created RetroShare?$q$, $q$RetroShare was founded in 2006 by a developer known by the handle drbob, with later contributions from other developers including one known as Crypton, who built the Qt graphical interface.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$What platforms does RetroShare support?$q$, $q$RetroShare is available on Windows, macOS, Linux, and Android.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Can I share files with people I'm not directly connected to?$q$, $q$Yes, RetroShare uses anonymous tunnels so users can reach friends-of-friends for chat and content, while still protecting the identity of who is sharing what.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Does RetroShare have a company behind it?$q$, $q$No, RetroShare is a volunteer-maintained open-source project with no corporate entity, headquarters, or formal support contracts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Is RetroShare good for large file transfers?$q$, $q$Yes, it uses swarming techniques similar to BitTorrent, which is well suited to sharing large files efficiently among friends.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Private encrypted group communication$q$, $q$Small trusted groups use RetroShare for encrypted chat, calls, and file sharing without relying on a company-run server.$q$, $q$Privacy-conscious individuals and groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Censorship-resistant forums$q$, $q$Communities use RetroShare's decentralized forums and boards to discuss topics that might be restricted or removed on centralized platforms.$q$, $q$Activists and community organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Large file sharing among friends$q$, $q$Users share large files, such as media libraries or backups, directly between trusted friend nodes using swarming transfers.$q$, $q$Technical users and file-sharing communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Encrypted friend-to-friend chat and messaging","Decentralized forums and boards","Swarming file sharing","Optional VoIP voice and video plugin","No subscription fees or ads"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RetroShare is an open-source, decentralized communication platform founded in 2006 by a developer known as drbob, designed to let people communicate and share files securely and privately with friends they explicitly trust, without routing traffic through centralized servers.$q$, $q$The project is entirely community-maintained and free, distributed for Windows, macOS, Linux, and Android, with development coordinated publicly on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RetroShare combines encrypted chat (including distant chat to friends-of-friends), decentralized forums and boards that sync offline, a store-and-forward private messaging system, BitTorrent-style swarming file sharing for large files, and an optional VoIP plugin for encrypted voice and video calls.$q$, $q$All connections are secured using OpenPGP and OpenSSL, and traffic beyond a user's direct friends is routed through anonymous tunnels, so only direct friends can see what a user shares or downloads.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RetroShare is completely free and open source, with no subscription fees, in-app purchases, advertising, or hidden costs of any kind.$q$, $q$Because it is a volunteer-maintained project rather than a commercial product, there are no paid tiers, enterprise plans, or support contracts; users rely on community documentation and forums for help.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('456fbc5c-1126-4664-96da-4a376804c0f8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Full eDiscovery Reference Model coverage$q$, $q$Supports every stage from legal hold and data preservation through review, analysis, and courtroom presentation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$aji generative AI layer$q$, $q$Reveal's proprietary generative AI engine assists with document review, summarization, and analysis.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$ASK natural-language search$q$, $q$Lets legal teams query large document sets in plain English rather than complex boolean search strings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$AI-powered document review workflows$q$, $q$Applies predictive coding, concept clustering, and relevance scoring to prioritize the most important documents at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Pre-built AI model library$q$, $q$Over 25 ready-to-use AI models cover common legal scenarios such as antitrust investigations, PII identification, and HR matters.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Legal hold and investigations tools$q$, $q$Manages custodian notifications, data preservation, and internal investigations alongside core eDiscovery workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Enterprise-scale customer base$q$, $q$Used by more than 4,000 customers across over 50 countries, from corporate legal teams to law firms and government agencies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Brainspace-derived analytics engine$q$, $q$Incorporates the AI and analytics technology from the 2021 Brainspace merger for concept clustering and pattern detection.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Comprehensive platform covering the entire eDiscovery lifecycle in one system$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Advanced generative AI tools (aji, ASK) built specifically for legal document review$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Large pre-built AI model library reduces setup time for common legal scenarios$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Established enterprise customer base and backing from K1 Investment Management$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Deep domain focus on legal, compliance, and investigations use cases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$No public self-serve pricing, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Built for enterprise legal teams and large matters, likely overkill for very small firms or simple cases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$As a specialized legal AI platform, it has a learning curve for non-legal-technology users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Cost likely scales significantly with data volume, which can be hard to predict upfront$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Frequently confused by name with unrelated products, such as the open-source reveal.js presentation framework$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$What is Reveal (RevealData) used for?$q$, $q$Reveal is an AI-powered eDiscovery, document review, legal hold, and investigations platform used by corporate legal teams, law firms, and government agencies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Is Reveal the same company as reveal.js?$q$, $q$No. Reveal/RevealData is a legal technology and eDiscovery company; reveal.js is an unrelated, unaffiliated open-source HTML presentation framework created by developer Hakim El Hattab.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$When was Reveal founded?$q$, $q$Reveal traces back to 2009 under founder and CEO Wendell Jisa, and took its current combined form in January 2021 after merging with Brainspace.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$What is aji in the Reveal platform?$q$, $q$aji is Reveal's proprietary generative AI layer used for document review and analysis within its eDiscovery platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$How much does Reveal cost?$q$, $q$Reveal uses custom, quote-based enterprise pricing tied to data volume, user count, and modules needed; it does not publish flat self-serve pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Where is Reveal headquartered?$q$, $q$Reveal (RevealData) is headquartered in Chicago, Illinois.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$What was the Brainspace merger?$q$, $q$In January 2021, Reveal merged with Brainspace, an AI and analytics company, backed by more than 200 million dollars in investment from K1 Investment Management, to form the combined Reveal platform.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Corporate litigation and eDiscovery$q$, $q$Corporate legal departments use Reveal to identify, collect, review, and produce documents for litigation and regulatory matters.$q$, $q$Corporate legal and compliance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Law firm document review at scale$q$, $q$Law firms and legal service providers use Reveal's AI-powered review workflows to prioritize and analyze large document sets faster.$q$, $q$Law firms and legal service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Internal and government investigations$q$, $q$Investigators use Reveal's AI models and analytics for scenarios like antitrust reviews, HR investigations, and PII identification.$q$, $q$Government agencies and corporate investigations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$Enterprise (Custom Quote)$q$, $q$Custom$q$, $q$Contract-based$q$, NULL, $q$["Pricing based on data volume, users, and modules needed","Full eDiscovery Reference Model coverage","Access to aji generative AI and ASK natural-language search","Pre-built AI model library","Dedicated account and legal technology support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Reveal, marketed under the RevealData brand, is an AI-powered eDiscovery and legal investigations platform headquartered in Chicago, Illinois. The company traces back to 2009 under founder and CEO Wendell Jisa, and took its current shape in January 2021 when Reveal merged with the AI analytics company Brainspace, backed by more than 200 million dollars from K1 Investment Management.$q$, $q$Reveal serves corporate legal departments, law firms, legal service providers, and government agencies, reporting over 4,000 customers across more than 50 countries and a workforce of roughly 500 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Reveal covers the entire eDiscovery Reference Model, from legal hold and data preservation through collection, processing, review, analysis, and production, and includes tools for presenting evidence at hearings and trials.$q$, $q$Its generative AI layer, aji, works alongside a natural-language query tool called ASK and a structured AI-powered document review workflow using predictive coding and concept clustering, plus a library of more than 25 pre-built AI models for common legal scenarios like antitrust investigations and PII detection.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9f433b75-2930-48b2-9563-119f142dab72', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Reveal does not publish self-serve pricing; as an enterprise eDiscovery platform, costs are quoted based on data volume, number of users, and the specific modules a legal team or law firm needs.$q$, $q$Prospective customers work directly with Reveal's sales team to scope pricing for a given matter, case, or ongoing subscription relationship.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Markdown slide authoring$q$, $q$Write slide content in plain Markdown instead of manually authoring HTML for every slide.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Nested slide navigation$q$, $q$Organize content into vertical and horizontal slide stacks for structured, deep-diving presentations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Auto-Animate transitions$q$, $q$Automatically animates matching elements between consecutive slides for smooth, professional-looking transitions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Speaker view with notes and timer$q$, $q$A dedicated presenter view shows speaker notes, a countdown timer, and a preview of the next slide.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$PDF export$q$, $q$Export any presentation to PDF for offline sharing, printing, or archiving.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$LaTeX and code syntax highlighting$q$, $q$Built-in support for LaTeX typesetting and syntax-highlighted code blocks makes it popular for technical talks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Extensive JavaScript API$q$, $q$A rich API and plugin ecosystem let developers customize behavior, add interactivity, or embed live content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Responsive, web-native slides$q$, $q$Presentations scale to fit any screen and can include anything a normal web page can, including embedded iframes and custom CSS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Highly customizable since presentations are built from standard HTML, CSS, and JavaScript$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Popular among developers and technical speakers for code-based, version-controllable slide decks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Strong built-in support for code syntax highlighting and LaTeX, ideal for technical content$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Large, long-running open-source community with tens of thousands of GitHub stars$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Requires comfort with HTML, CSS, and optionally JavaScript, unlike drag-and-drop slide tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$No built-in cloud collaboration features found in commercial presentation software$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Design polish depends on the author's own CSS and theme choices rather than a built-in design assistant$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$No official commercial support; help comes from community docs and the open-source repository$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Steeper learning curve for non-technical presenters compared to tools like PowerPoint or Google Slides$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Is reveal.js free?$q$, $q$Yes, reveal.js is completely free and open source under the MIT license, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Who created reveal.js?$q$, $q$reveal.js was created by developer Hakim El Hattab, who first released it in 2011 and continues to maintain it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Do I need to know how to code to use reveal.js?$q$, $q$Basic slide decks can be written in Markdown with minimal coding, but customizing behavior or advanced layouts benefits from knowledge of HTML, CSS, and JavaScript.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Is reveal.js the same as Reveal/RevealData?$q$, $q$No. reveal.js is an unrelated, unaffiliated open-source HTML presentation framework; Reveal/RevealData is a separate commercial legal eDiscovery and AI document review company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Can reveal.js presentations be exported to PDF?$q$, $q$Yes, reveal.js includes built-in PDF export for offline sharing or printing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Does reveal.js support speaker notes?$q$, $q$Yes, it includes a dedicated speaker view with notes, a timer, and a preview of the upcoming slide.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Where is reveal.js hosted?$q$, $q$The reveal.js source code is hosted on GitHub under hakimel/reveal.js and distributed via npm.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Technical conference talks$q$, $q$Developers and technical speakers use reveal.js to build code-based slide decks with syntax-highlighted code and LaTeX support.$q$, $q$Developers and conference speakers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Educational and academic presentations$q$, $q$Educators use reveal.js's Markdown authoring and LaTeX typesetting to build lecture slides with mathematical content.$q$, $q$Teachers and academic presenters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Embedding live or interactive content in slides$q$, $q$Presenters use reveal.js's web-native architecture to embed live demos, iframes, or interactive visualizations directly into slides.$q$, $q$Product teams and technical demo presenters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT-licensed HTML presentation framework","Markdown slide authoring","PDF export","Speaker notes and presenter view","Extensive JavaScript API and plugin ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$reveal.js is an open-source HTML presentation framework created by developer Hakim El Hattab, who released the first version in 2011 and still actively maintains the project. It is distributed under the MIT license and lets anyone build interactive, code-based slide presentations that run in any web browser.$q$, $q$Because a reveal.js presentation is fundamentally an HTML page, presenters have full access to web technologies like CSS, JavaScript, and iframes to customize and extend their slides in ways not possible in traditional slide software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$reveal.js supports nested vertical and horizontal slides, Markdown-based slide authoring, an Auto-Animate feature for smooth element transitions, PDF export, LaTeX typesetting, and syntax-highlighted code blocks.$q$, $q$It also includes a dedicated speaker view with a timer and next-slide preview, custom themes and transitions, parallax backgrounds, configurable keyboard bindings, and an extensive JavaScript API and plugin system for further customization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$reveal.js is completely free and open source under the MIT license, with no paid tiers, subscriptions, or licensing fees of any kind.$q$, $q$Because it is distributed as a code library rather than a hosted product, the only potential costs come from optional hosting for published presentations, which developers can handle through any static web host of their choice.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f61c5d6-c000-4e54-918d-cc68123a94de', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$iPad-native point-of-sale$q$, $q$Built specifically around Apple's iPad for a mobile, touch-friendly checkout experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Offline mode$q$, $q$Continues processing sales and transactions even when internet connectivity is lost, then syncs once reconnected.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Multi-location management$q$, $q$Centralizes reporting, inventory, and employee management across multiple restaurant or retail locations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Inventory management$q$, $q$Tracks stock levels, ingredients, and vendor orders alongside sales data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Employee management$q$, $q$Handles scheduling, time tracking, and permissions for staff across locations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Kitchen display system support$q$, $q$Integrates with KDS screens for restaurant order routing, available as an add-on.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$API access$q$, $q$Offers API connectivity for custom integrations, available as an additional paid feature.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Reporting and analytics$q$, $q$Provides sales, labor, and inventory analytics across single or multiple locations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Strong offline processing capability, valuable for locations with unreliable internet$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Robust multi-location management suited to growing restaurant or retail chains$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$One of the most established iPad POS platforms with over a decade in the market$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Now backed by Shift4's payments infrastructure following the 2024 acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Comprehensive feature set spanning POS, inventory, employee management, and CRM$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Requires a three-year contract with aggressive early-termination fees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Minimum two-terminal requirement raises the effective entry cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Many features, like API access and extra KDS screens, cost extra on top of the base subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Product roadmap uncertainty following the 2024 Shift4 acquisition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Long-term contract structure is less flexible than newer, month-to-month POS competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Who owns Revel Systems now?$q$, $q$Shift4 acquired Revel Systems in June 2024 for approximately 245 million dollars.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$When was Revel Systems founded?$q$, $q$Revel Systems was founded in 2010 in San Francisco by Lisa Falzone and Chris Ciabarra.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$How much does Revel Systems cost?$q$, $q$Pricing starts at roughly 99 dollars per month per terminal on annual billing, typically requiring a minimum of two terminals and a three-year contract.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Does Revel Systems work offline?$q$, $q$Yes, Revel is known for its offline mode, which lets locations keep processing sales when internet connectivity drops.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Is Revel Systems good for multi-location businesses?$q$, $q$Yes, it is commonly used by mid-size and larger restaurant and retail operators specifically for its multi-location management and reporting capabilities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Are there extra fees beyond the base Revel subscription?$q$, $q$Yes, features like API access, additional kitchen display screens, and enterprise-level reporting are typically billed as add-ons.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Where is Revel Systems headquartered?$q$, $q$Revel Systems is headquartered in Atlanta, Georgia, after originally being founded in San Francisco, California.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Multi-location restaurant operations$q$, $q$Restaurant groups use Revel to manage POS, inventory, and reporting consistently across several locations from one system.$q$, $q$Multi-location restaurant operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Retail point-of-sale with inventory tracking$q$, $q$Retail businesses use Revel's POS and inventory management to track stock and sales across stores.$q$, $q$Retail store owners and managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$High-reliability checkout in unstable connectivity environments$q$, $q$Businesses in locations with unreliable internet use Revel's offline mode to keep processing transactions without interruption.$q$, $q$Restaurant and retail operators in low-connectivity areas$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$Standard$q$, $q$$99+$q$, $q$per month per terminal (annual billing)$q$, NULL, $q$["Point-of-sale software","Inventory management","Employee management","Reporting and analytics","Minimum 2 terminals, 3-year contract typical"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Revel Systems is a cloud-based, iPad-native point-of-sale platform founded in 2010 in San Francisco by Lisa Falzone and Chris Ciabarra, among the first companies to build a POS system specifically for Apple's iPad. The company's headquarters later moved to Atlanta, Georgia, while it maintained a presence in San Francisco as it grew into a multi-location restaurant and retail platform.$q$, $q$In June 2024, payments company Shift4 acquired Revel Systems for approximately 245 million dollars, bringing Revel's POS technology into Shift4's broader payments portfolio.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Revel's platform combines point-of-sale software with inventory management, employee scheduling, customer relationship management, and multi-location reporting and analytics, built for both restaurant and retail environments.$q$, $q$It is known for strong offline capabilities, letting locations keep processing sales even when internet connectivity drops, along with support for kitchen display systems and API access for custom integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67824c5f-fc78-40c9-a0e2-86281d436d4e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Revel Systems pricing starts at approximately 99 dollars per month per terminal on annual billing, typically requiring a minimum of two terminals and a three-year contract with early-termination fees.$q$, $q$Additional features, such as API access, extra kitchen display screens, advanced inventory counting, and enterprise-level multi-location reporting, are billed as add-ons on top of the base subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Unified purchase API$q$, $q$Abstracts Apple StoreKit and Google Play Billing behind a single API for managing purchases and entitlements.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Cross-platform subscriber management$q$, $q$Tracks and manages subscriber status consistently across iOS, Android, and the web.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Native paywall editor$q$, $q$Build and test paywalls with templates and update them remotely without an app-store resubmission.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$A/B testing and remote configuration$q$, $q$Run experiments on pricing, paywalls, and offers with remote config changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Monetization analytics dashboard$q$, $q$Tracks more than 40 key monetization metrics in one place.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$MMP integrations$q$, $q$Pre-built integrations with mobile measurement partners provide real-time purchase attribution data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Open-source SDKs$q$, $q$SDKs for all major platforms are open source, giving developers visibility and flexibility in their billing integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Lifecycle campaign triggers$q$, $q$Event-based triggers support automated retention and win-back campaigns tied to subscription events.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Free tier covers apps up to 2,500 dollars in monthly tracked revenue, ideal for early-stage apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Revenue-share pricing scales with actual app revenue rather than charging flat fees regardless of usage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Saves significant engineering time by abstracting Apple and Google billing complexity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Strong monetization and analytics tooling beyond just purchase handling, including paywalls and A/B testing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Open-source SDKs and a widely adopted platform, used by more than 30,000 apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$1 percent revenue-share fee on high-revenue apps can become a meaningful cost at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Enterprise pricing requires a custom sales conversation for high-volume or specialized needs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Adds a third-party dependency for subscription infrastructure that is critical to app revenue$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Growth Tools pricing path requires managing your own backend infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Primarily focused on mobile subscription apps, less relevant for non-subscription business models$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$What does RevenueCat do?$q$, $q$RevenueCat is a backend-as-a-service platform that unifies in-app purchase and subscription management across iOS, Android, and the web, abstracting away Apple StoreKit and Google Play Billing complexity.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$How much does RevenueCat cost?$q$, $q$RevenueCat's Pro plan is free for up to 2,500 dollars in monthly tracked revenue, then charges 1 percent of tracked revenue above that threshold, with custom Enterprise pricing for larger apps.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Who founded RevenueCat?$q$, $q$RevenueCat was founded in 2017 by Jacob Eiting and Miguel Carranza and is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Does RevenueCat charge per transaction?$q$, $q$No, RevenueCat's core pricing is based on a percentage of monthly tracked revenue rather than per-transaction fees or seat licenses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$How many apps use RevenueCat?$q$, $q$RevenueCat reports powering subscription infrastructure for more than 30,000 apps.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Does RevenueCat support the web as well as mobile?$q$, $q$Yes, RevenueCat manages purchases and subscriber entitlements across iOS, Android, and the web.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$What is RevenueCat's paywall editor?$q$, $q$It is a native tool for building and updating in-app paywalls with templates and remote configuration, without needing an app-store resubmission for changes.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Cross-platform subscription management$q$, $q$Mobile app developers use RevenueCat to manage subscriber entitlements consistently across iOS, Android, and the web from a single backend.$q$, $q$Mobile app developers and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Paywall experimentation$q$, $q$Product and growth teams use RevenueCat's paywall editor and A/B testing tools to optimize conversion without shipping new app builds.$q$, $q$Product and growth teams at app companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Subscription analytics and reporting$q$, $q$App publishers use RevenueCat's dashboard to track monetization metrics like churn, LTV, and MRR across platforms in one place.$q$, $q$App publishers and data/analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Pro$q$, $q$Free up to $2,500 MTR, then 1% of tracked revenue above that$q$, $q$usage-based (monthly)$q$, NULL, $q$["Unified subscription backend","Open-source SDKs for all platforms","Comprehensive REST API","Pre-built MMP integrations","A/B testing with remote configuration","Native paywall editor","40+ monetization metrics dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Growth Tools$q$, $q$1% of MTR on conversions via specific tools$q$, $q$usage-based (monthly)$q$, NULL, $q$["Use your own backend infrastructure","Pay only on conversions from paywalls or web-to-app funnels","Access to paywall editor and growth tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$Enterprise$q$, $q$Custom$q$, $q$Contract-based$q$, NULL, $q$["Volume discounts","Flexible tracking configurations","Dedicated support","Custom SLAs for high-volume applications"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RevenueCat is a backend-as-a-service platform for in-app purchases and subscriptions, founded in 2017 by Jacob Eiting and Miguel Carranza and headquartered in San Francisco, California. It gives mobile developers a unified API for managing purchases and entitlements across iOS, Android, and the web instead of building separate integrations for Apple's StoreKit and Google Play Billing.$q$, $q$Backed by Y Combinator, RevenueCat has grown to power subscription infrastructure for more than 30,000 apps, with a team of roughly 150 to 170 employees as of recent reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RevenueCat's core product includes open-source SDKs, a unified subscription backend, a REST API, and pre-built MMP integrations for real-time purchase attribution across platforms.$q$, $q$Additional tools include A/B testing with remote configuration, a native paywall editor with templates, audience segmentation, a dashboard with more than 40 monetization metrics, and event-based lifecycle campaign triggers for retention and win-back flows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d89ed73f-80e0-4221-8c89-5c539a41247e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RevenueCat's Pro plan is free for apps with up to 2,500 dollars in monthly tracked revenue, then charges 1 percent of tracked revenue above that threshold, with no seat licenses or per-transaction fees.$q$, $q$An alternative Growth Tools pricing path lets teams use their own backend and pay 1 percent of MTR only on conversions driven by specific tools like the paywall editor, while a custom-priced Enterprise plan adds volume discounts, dedicated support, and custom SLAs for high-volume apps.$q$]::text[], 2);
